Prolog:
sPrefix = Trim(pPrefix);
If(sPrefix @= '');
  sPrefix = 'IMF';
EndIf;

sDimensionCode = Trim(pDimensionCode);
sMasterDimensionName = Trim(pMasterDimensionName);
sCreatePhysicalDimension = Upper(Trim(pCreatePhysicalDimension));
sIsActive = Upper(Trim(pIsActive));
sValidationProcess = Trim(pValidationProcess);
sImpactProcess = Trim(pImpactProcess);
sExportProfile = Trim(pExportProfile);

If(sCreatePhysicalDimension @= '');
  sCreatePhysicalDimension = 'Y';
EndIf;
If(sIsActive @= '');
  sIsActive = 'Y';
EndIf;
If(sValidationProcess @= '');
  sValidationProcess = sPrefix | '.P.Validate.Technical';
EndIf;
If(sImpactProcess @= '');
  sImpactProcess = sPrefix | '.P.Impact.RunAll';
EndIf;
If(sExportProfile @= '');
  sExportProfile = 'DEFAULT';
EndIf;

If(sDimensionCode @= '');
  ProcessBreak;
EndIf;
If(sMasterDimensionName @= '');
  sMasterDimensionName = sDimensionCode;
EndIf;

sDimDimension = sPrefix | '.D.Dimension';
sDimConfigKey = sPrefix | '.D.ConfigKey';
sCubeConfig = sPrefix | '.C.Config';
sTemplateCode = '__Template.ManagedDimension';

If(DimensionExists(sDimDimension) = 0);
  ProcessBreak;
EndIf;
If(DimensionExists(sDimConfigKey) = 0);
  ProcessBreak;
EndIf;
If(CubeExists(sCubeConfig) = 0);
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimDimension, sTemplateCode) = 0);
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimDimension, sDimensionCode) = 1);
  ProcessBreak;
EndIf;

If(sCreatePhysicalDimension @= 'Y');
  ExecuteProcess(
    sPrefix | '.P.Dimension.Create',
    'pPrefix', sPrefix,
    'pTargetDimension', sMasterDimensionName
  );
ElseIf(DimensionExists(sMasterDimensionName) = 0);
  ProcessBreak;
EndIf;

If(DimensionElementExists(sDimDimension, 'All Managed Dimensions') = 0);
  DimensionElementInsert(sDimDimension, '', 'All Managed Dimensions', 'C');
EndIf;

DimensionElementInsert(sDimDimension, '', sDimensionCode, 'N');
DimensionElementComponentAdd(sDimDimension, 'All Managed Dimensions', sDimensionCode, 1);

AttrPutS(sMasterDimensionName, sDimDimension, sDimensionCode, 'MasterDimensionName');
AttrPutS('', sDimDimension, sDimensionCode, 'ActiveVersion');
AttrPutS('', sDimDimension, sDimensionCode, 'LastPublishedVersion');
AttrPutS('', sDimDimension, sDimensionCode, 'LastArchivedDimension');
AttrPutS(sValidationProcess, sDimDimension, sDimensionCode, 'ValidationProcess');
AttrPutS(sImpactProcess, sDimDimension, sDimensionCode, 'ImpactProcess');
AttrPutS(sExportProfile, sDimDimension, sDimensionCode, 'ExportProfile');
AttrPutS(sIsActive, sDimDimension, sDimensionCode, 'IsActive');

nConfigIndex = 1;
nConfigCount = DIMSIZ(sDimConfigKey);
While(nConfigIndex <= nConfigCount);
  sConfigKey = DIMNM(sDimConfigKey, nConfigIndex);
  If(sConfigKey @<> 'All Config Keys');
    sConfigValue = CellGetS(sCubeConfig, sTemplateCode, sConfigKey);
    CellPutS(sConfigValue, sCubeConfig, sDimensionCode, sConfigKey);
  EndIf;
  nConfigIndex = nConfigIndex + 1;
End;

ExecuteProcess(
  sPrefix | '.P.Log.Event',
  'pPrefix', sPrefix,
  'pSeverity', 'INFO',
  'pObjectType', 'DIMENSION',
  'pObjectName', sDimensionCode,
  'pMessage', 'Managed dimension onboarded with master dimension ' | sMasterDimensionName | '.',
  'pRunId', sDimensionCode
);
